INSERT INTO blocks VALUES(1,2,1,'paragraph',NULL,NULL,'Știai că sistemele AI au fost create (și) de programatori? Cel puțin pe moment, încă este nevoie de programatori pentru a integra AI cu procesele și software-ul existent. Acest capitol este dedicat celor care vor să vadă cu ochii lor mici bucăți dintr-o asemenea integrare. Dacă ești decident, fluxul minim (dar complet) de implementare din 4.1 este pentru tine. Sau poți sări la capitolul următor.',NULL,NULL,NULL);
