INSERT INTO elements VALUES(47,37,1,'list_item',unistr('<strong>\u000d\u000a                                Deep Learning nu este un singur proces, ci o succesiune de pași:\u000d\u000a                            </strong>\u000d\u000a\u000d\u000a                            definirea obiectivelor, curățarea și conectarea datelor, definirea evenimentelor,\u000d\u000a                            generarea candidaților, ranking și post-procesare, integrare în UX, feedback explicit, monitorizare.'),NULL,NULL,NULL);
INSERT INTO elements VALUES(48,37,2,'list_item',unistr('<strong>\u000a<i class="fa-regular fa-gear icon-gradient"></i> Build (custom)\u000d\u000a                            </strong>\u000d\u000a\u000d\u000a                            oferă control maxim, dar cere echipă tehnică dedicată și disciplinată, în plus față de\u000d\u000a                            efortul întregii companii.'),NULL,NULL,NULL);
INSERT INTO elements VALUES(49,37,3,'list_item',unistr('<strong>\u000a<i class="fa-regular fa-cloud icon-gradient"></i> Managed (Cloud Native)\u000d\u000a                            </strong>\u000d\u000a\u000d\u000a                            externalizează o parte din complexitate, dar necesită decizii la nivelul companiei și\u000d\u000a                            configurare tehnică atentă.'),NULL,NULL,NULL);
INSERT INTO elements VALUES(50,37,4,'list_item','Ambele variante depind de curățarea datelor și <code>A/B testing</code> pentru a obține rezultate.',NULL,NULL,NULL);
INSERT INTO elements VALUES(51,39,1,'list_item','Exemplele sunt în pseudocod, pentru a <strong>arăta în practică</strong> câteva bucăți cheie de logică recomandări AI.',NULL,NULL,NULL);
INSERT INTO elements VALUES(52,39,2,'list_item',unistr('Pentru volume mari de date (Big Data) logica tinde să se mute din <strong><code>Python</code></strong> în <strong><code>Spark</code></strong> sau <strong><code>SQL</code></strong>\u000d\u000a                            pentru a evita iterări pe milioane de produse. Vezi exemple la <a href="#market-basket-analysis-spark-sql">Cap 4.2.4</a>.'),NULL,NULL,NULL);
INSERT INTO elements VALUES(53,39,3,'list_item','<em>Exemplele de cod sunt simplificate pentru claritate și necesită adaptare la mediul de producție specific, plus <strong>autentificare/IAM, protecție pentru concurență, excepții, reîncercări</strong> etc.</em>',NULL,NULL,NULL);
INSERT INTO elements VALUES(54,41,1,'code_snippet',unistr('from dataclasses import dataclass\u000d\u000a\u000d\u000a@dataclass\u000d\u000aclass Candidate:\u000d\u000a    sku: str\u000d\u000a    score_ai: float\u000d\u000a    stock: int\u000d\u000a    margin_pct: float\u000d\u000a    forbidden: bool = False\u000d\u000a\u000d\u000adef apply_guardrails(\u000d\u000a    candidates: list[Candidate],\u000d\u000a    min_margin_pct: float,\u000d\u000a    min_score_ai: float,\u000d\u000a    max_items: int = 10,\u000d\u000a) -> list[Candidate]:\u000d\u000a    # 1. filtram produsele interzise, fara stoc sau sub marja minima\u000d\u000a    filtered = [\u000d\u000a        c for c in candidates\u000d\u000a        if not c.forbidden\u000d\u000a        and c.stock > 0\u000d\u000a        and c.margin_pct >= min_margin_pct\u000d\u000a        and c.score_ai >= min_score_ai\u000d\u000a    ]\u000d\u000a\u000d\u000a    # 2. daca dupa filtrare lista este prea scurta, completam cu fallback intern (get_top_selling_products)\u000d\u000a    if len(filtered) < max_items:\u000d\u000a        missing = max_items - len(filtered)\u000d\u000a        exclude_skus = {c.sku for c in filtered}\u000d\u000a        filtered.extend(get_top_selling_products(exclude_skus=exclude_skus, limit=missing))\u000d\u000a    # 3. sortam dupa scorul AI și limitam\u000d\u000a    filtered.sort(key=lambda c: c.score_ai, reverse=True)\u000d\u000a    return filtered[:max_items]'),NULL,unistr('Snippet: pipeline care primește candidați cu scor și aplică guardrails\u000d\u000a                            înainte de a trimite către UI'),'{"language": "python"}');
INSERT INTO elements VALUES(55,41,2,'note_item',unistr('Guardrails sunt o\u000d\u000a\u000d\u000a                                <strong>\u000d\u000a                                    funcție distinctă\u000d\u000a                                </strong>\u000d\u000a\u000d\u000a                                în pipeline.'),NULL,'Note',NULL);
INSERT INTO elements VALUES(56,41,3,'note_item',unistr('<strong>\u000d\u000a                                    Fallback\u000d\u000a                                </strong>\u000d\u000a\u000d\u000a                                (pasul 2) e la fel de important ca filtrarea.'),NULL,'Note',NULL);
INSERT INTO elements VALUES(57,41,4,'note_item','Asigurați-vă că  <code>get_top_selling_products()</code> aplică aceleași guardrails',NULL,'Note',NULL);
INSERT INTO elements VALUES(58,42,1,'list_item',unistr('Pe lângă filtrele la runtime, poți face verificări offline care detectează\u000d\u000a                        recomandările nedorite (ex: cu marjă negativă).'),NULL,NULL,NULL);
INSERT INTO elements VALUES(59,42,2,'code_snippet',unistr('SELECT\u000d\u000a  r.account_id\u000d\u000a  , r.scenario\u000d\u000a  , r.sku_recomandat\u000d\u000a  , r.score_ai\u000d\u000a  , p.margin_pct\u000d\u000a  , r.created_at\u000d\u000aFROM recommendations_log r\u000d\u000aJOIN products p ON r.sku_recomandat = p.sku\u000d\u000aWHERE \u000d\u000a  p.margin_pct <= 0.15 -- sau prag parametrizabil\u000d\u000a  AND r.created_at > (NOW() - INTERVAL ''1 DAY'')\u000d\u000aORDER BY r.created_at DESC\u000d\u000aLIMIT 100;'),NULL,'Snippet: pseudocod de detecție recomandări cu marjă sub prag','{"language": "sql"}');
INSERT INTO elements VALUES(60,42,3,'note_item',unistr('Acest tip de interogări generează un\u000d\u000a\u000d\u000a                                <strong>\u000d\u000a                                    raport al calității\u000d\u000a                                </strong> într-un dashboard de analiză.'),NULL,'Note',NULL);
INSERT INTO elements VALUES(61,42,4,'note_item','Decizi în ce măsură guardrails-urile <strong>sunt suficiente sau mai trebuie definite</strong>.',NULL,'Note',NULL);
INSERT INTO elements VALUES(62,43,1,'list_item',unistr('Fără ingestie corectă, recomandările vor fi greșite. Pe lângă problema latenței, este importantă\u000d\u000a                        consistența datelor, toate evenimentele trebuie să aibă detaliile minime și să fie identificate unic pentru idempotență.'),NULL,NULL,NULL);
INSERT INTO elements VALUES(63,43,2,'code_snippet',unistr('from pydantic import BaseModel, Field\u000d\u000afrom datetime import datetime\u000d\u000afrom typing import Optional\u000d\u000a\u000d\u000aclass InventoryUpdateEvent(BaseModel):\u000d\u000a    sku: str\u000d\u000a    new_stock: int = Field(ge=0)\u000d\u000a    source: Optional[str] = None     # ex: "WMS", "ERP", "Manual"\u000d\u000a    updated_at: datetime\u000d\u000a    idempotency_key: str = Field(min_length=8)\u000d\u000a\u000d\u000a    #aici se poate adauga logica de Feature (atribut) pentru care apoi se defineste pipeline-ul'),NULL,'Snippet: structură de eveniment de actualizare stoc, validat înainte de pipeline / Feature Store','{"language": "python"}');
INSERT INTO elements VALUES(64,43,3,'note_item','Validează datele minime (<code>new_stock</code> nu e negativ) și permite ingestia în orice ordine prin <em>updated_at</em>.',NULL,'Note',NULL);
INSERT INTO elements VALUES(65,43,4,'note_item','În B2B <code>new_stock</code> trebuie calculat de obicei ca stoc real (scriptic - rezervat) sau chiar liber la raft (din WMS).',NULL,'Note',NULL);
INSERT INTO elements VALUES(66,43,5,'note_item','<em>idempotency_key</em> asigură că la retry/trimitere dublată a aceluiași update de stoc, sistemul îl poate procesa o singură dată.',NULL,'Note',NULL);
INSERT INTO elements VALUES(67,44,1,'code_snippet',unistr('INSERT INTO inventory (sku, stock, updated_at)\u000d\u000aVALUES (:sku, :stock, :updated_at)\u000d\u000aON CONFLICT (sku)\u000d\u000aDO UPDATE SET\u000d\u000a  stock = EXCLUDED.stock\u000d\u000a  , updated_at = EXCLUDED.updated_at\u000d\u000aWHERE \u000d\u000a    inventory.updated_at IS NULL \u000d\u000a    OR inventory.updated_at < EXCLUDED.updated_at;'),NULL,'Snippet: pseudocod de Postgres pentru actualizare stoc. În BigQuery folosiți MERGE','{"language": "sql"}');
INSERT INTO elements VALUES(68,44,2,'note_item','Idempotența se poate implementa suplimentar cu un tabel de deduplicare sau un câmp (Ex: <em>last_event_id</em>).',NULL,'Note',NULL);
INSERT INTO elements VALUES(69,44,3,'note_item','Poți determina dacă produsul e eligibil pentru recomandări (<em>stock &gt; 0</em>) și îl marchezi.',NULL,'Note',NULL);
INSERT INTO elements VALUES(70,44,4,'note_item','În caz de modificare, declanșezi un task care invalidează cache-ul local pentru el.',NULL,'Note',NULL);
INSERT INTO elements VALUES(71,45,1,'code_snippet',unistr('SELECT\u000d\u000a  i.sku\u000d\u000a  , i.stock AS stock_official\u000d\u000a  , c.stock_cache AS stock_recommender\u000d\u000aFROM inventory i\u000d\u000aJOIN recommender_cache c ON i.sku = c.sku\u000d\u000aWHERE i.stock <> c.stock_cache;'),NULL,'Snippet: pseudocod pentru detecția diferențelor între stocul oficial și cache-ul local de recomandări','{"language": "sql"}');
INSERT INTO elements VALUES(72,45,2,'note_item',unistr('Investighezi unde ingestia real-time nu funcționează. Ex: update-uri\u000d\u000a                                pierdute, update-uri netrimise.'),NULL,'Note',NULL);
INSERT INTO elements VALUES(73,45,3,'note_item','Este recomandat ca sistemul să detecteze problemele înainte ca ele să fie raportate de clienți sau agenți.',NULL,'Note',NULL);
INSERT INTO elements VALUES(74,47,1,'code_snippet',unistr('from enum import Enum\u000d\u000a\u000d\u000aclass Scenario(Enum):\u000d\u000a    SIMILAR_ITEMS = "similar_items"\u000d\u000a    CART_ADDONS = "cart_addons"\u000d\u000a    SUBSTITUTES = "substitutes"\u000d\u000a\u000d\u000a# Registry de mapare scenariu -> model\u000d\u000aMODEL_REGISTRY = {\u000d\u000a    Scenario.SIMILAR_ITEMS:  "models/similar_items_v3",\u000d\u000a    Scenario.CART_ADDONS:    "models/cart_addons_v5",\u000d\u000a    Scenario.SUBSTITUTES:    "models/substitutes_v2",\u000d\u000a}\u000d\u000a\u000d\u000a# Daca folosesti un Feature Store, poti avea un registry separat pentru versiunile serviciilor scenariilor\u000d\u000aFS_SERVICE_REGISTRY = {\u000d\u000a    Scenario.SIMILAR_ITEMS:  "similar_items_service_v1",\u000d\u000a    Scenario.CART_ADDONS:    "cart_addons_service_v2",\u000d\u000a    Scenario.SUBSTITUTES:    "substitutes_service_v1",\u000d\u000a}\u000d\u000a\u000d\u000adef recommend_for_scenario(\u000d\u000a    scenario: Scenario,\u000d\u000a    account_id: str,\u000d\u000a    context: dict,\u000d\u000a) -> list[str]:\u000d\u000a    model_path = MODEL_REGISTRY[scenario]\u000d\u000a    \u000d\u000a    full_context = context.copy()\u000d\u000a    # interactiune cu Feature store (conceptual): mai intai obtii detaliile din store, apoi hidratezi contextul\u000d\u000a    # fs_service = FS_SERVICE_REGISTRY[scenario]\u000d\u000a    # account_features = call_fs_to_get_features(account_id=account_id, service=fs_service)\u000d\u000a    # full_context.update(account_features)\u000d\u000a\u000d\u000a    # Apel catre un model local sau un endpoint din cloud (cu toate datele necesare)\u000d\u000a    scores = call_model(model_path, account_id=account_id, inputs=full_context)\u000d\u000a    \u000d\u000a\u000d\u000a    # scores e lista de (sku, score_ai), ex: [("SKU1", 0.92), ("SKU2", 0.87)...]\u000d\u000a    ordered = sorted(scores, key=lambda x: x[1], reverse=True)\u000d\u000a    return [sku for sku, _ in ordered]'),NULL,'Snippet: router care decide modelul și sursa de date în funcție de context, cu variantă Feature Store','{"language": "python"}');
INSERT INTO elements VALUES(75,47,2,'note_item',unistr('<strong>Organizarea versiunilor de modele și servicii</strong> este esențială și e bine să fie decuplată.\u000d\u000a                        Dacă nu știi ce versiune rulează într-un scenariu, nu poți explica ce se întâmplă în producție.'),NULL,'Note',NULL);
INSERT INTO elements VALUES(76,47,3,'note_item','Prin hidratare afli foarte rapid înainte de inferența modelului ultimele atribute din Feature Store pentru acel account_id.',NULL,'Note',NULL);
INSERT INTO elements VALUES(77,47,4,'note_item','Logica de Feature Store este ascunsă, contractul <code>call_fs_to_get_features</code> include conectarea, caching și deserializarea (pentru latență minimă).',NULL,'Note',NULL);
INSERT INTO elements VALUES(78,48,1,'code_snippet',unistr('scenarios:\u000d\u000a  similar_items:\u000d\u000a    model: "models/similar_items_v3"\u000d\u000a    max_items: 10\u000d\u000a\u000d\u000a  cart_addons:\u000d\u000a    model: "models/cart_addons_v5"\u000d\u000a    max_items: 6\u000d\u000a\u000d\u000a  substitutes:\u000d\u000a    model: "models/substitutes_v2"\u000d\u000a    max_items: 5'),NULL,'Snippet: configurație de scenariu într-un fișier declarativ ( JSON  sau  YAML ), ușor de modificat de  arhitect sau product owner (vezi Cap.5.2.1)','{"language": "yaml"}');
INSERT INTO elements VALUES(79,48,2,'note_item','Router-ul din exemplul anterior poate citi această configurație la startup.',NULL,'Note',NULL);
INSERT INTO elements VALUES(80,48,3,'note_item','Poți folosi principii de <em>Convention over Configuration</em> (ex: numele scenariului să corespundă numelui modelului, <em>similar_items</em> să fie și în numele store-ului de audit etc).',NULL,'Note',NULL);
INSERT INTO elements VALUES(81,49,1,'list_item',unistr('În\u000d\u000a\u000d\u000a                            <strong>\u000d\u000a                                sistemul de recomandare:\u000d\u000a                            </strong>\u000d\u000a\u000d\u000a                            ce pachet propun pentru coșul sau oferta curentă.'),NULL,NULL,NULL);
INSERT INTO elements VALUES(82,49,2,'list_item','În <strong>data warehouse</strong>: ce propuneri recomandăm să devină pachete permanente în aplicație.',NULL,NULL,NULL);
INSERT INTO elements VALUES(83,51,1,'list_item',unistr('<details class="ais_codeblock">\u000a<summary class="ais_codeblock__summary">\u000d\u000a                            Snippet: algoritm FPGrowth (Frequent Pattern Growth) pentru a găsi asocieri\u000d\u000a                        </summary>\u000a<pre class="ais_codeblock__pre"><code class="language-python" data-lang="python">\u000d\u000afrom pyspark.ml.fpm import FPGrowth\u000d\u000afrom pyspark.sql import SparkSession\u000d\u000a\u000d\u000aspark = SparkSession.builder.getOrCreate()\u000d\u000a\u000d\u000a# 1. Datele: fiecare rand este o tranzactie cu un array de SKU\u000d\u000a# schema: [order_id: string, items: array&lt;string&gt;]\u000d\u000adf_orders = spark.table("sales_history_clean")\u000d\u000a\u000d\u000a# 2. Configuram algoritmul FPGrowth\u000d\u000a# minSupport: produsele apar impreuna in X% din tranzactii\u000d\u000a# minConfidence: cine ia A, are X% sanse sa ia si B\u000d\u000afp_growth = FPGrowth(itemsCol="items", minSupport=0.001, minConfidence=0.2)\u000d\u000a\u000d\u000a# 3. Antrenam modelul distribuit\u000d\u000amodel = fp_growth.fit(df_orders)\u000d\u000a\u000d\u000a# 4. Extragem regulile de asociere (antecedent -&gt; consequent)\u000d\u000a# schema: [antecedent: [SKU_A], consequent: [SKU_B], confidence: 0.85, lift: 2.4]\u000d\u000aassociation_rules = model.associationRules\u000d\u000a\u000d\u000a# Salvam intr-un tabel temporar pentru procesare ulterioara\u000d\u000aassociation_rules.createOrReplaceTempView("raw_rules")\u000d\u000a    </code>\u000d\u000a    </pre>\u000a</details>\u000a<details class="ais_codeblock ais_codeblock--teal">\u000a<summary class="ais_codeblock__summary">\u000a<strong>Note</strong>\u000a</summary>\u000a<ul class="ais_codeblock__p">\u000a<li>Acest cod rulează distribuit pe un cluster de Spark (pentru o implementare Enterprise) și procesează istoricul rapid.</li>\u000a<li>Rezultatul brut trebuie rafinat cu reguli de business (guardrails) ulterior. </li>\u000a<li>În pre-procesare se pot îndepărta produsele prea comune care sunt zgomot statistic (en. <em>noise</em>): ambalaje, consumabile, transportul dacă are SKU în ERP. </li>\u000a</ul>\u000a</details>'),NULL,NULL,NULL);
INSERT INTO elements VALUES(84,51,2,'code_snippet',unistr('from pyspark.ml.fpm import FPGrowth\u000d\u000afrom pyspark.sql import SparkSession\u000d\u000a\u000d\u000aspark = SparkSession.builder.getOrCreate()\u000d\u000a\u000d\u000a# 1. Datele: fiecare rand este o tranzactie cu un array de SKU\u000d\u000a# schema: [order_id: string, items: array<string>]\u000d\u000adf_orders = spark.table("sales_history_clean")\u000d\u000a\u000d\u000a# 2. Configuram algoritmul FPGrowth\u000d\u000a# minSupport: produsele apar impreuna in X% din tranzactii\u000d\u000a# minConfidence: cine ia A, are X% sanse sa ia si B\u000d\u000afp_growth = FPGrowth(itemsCol="items", minSupport=0.001, minConfidence=0.2)\u000d\u000a\u000d\u000a# 3. Antrenam modelul distribuit\u000d\u000amodel = fp_growth.fit(df_orders)\u000d\u000a\u000d\u000a# 4. Extragem regulile de asociere (antecedent -> consequent)\u000d\u000a# schema: [antecedent: [SKU_A], consequent: [SKU_B], confidence: 0.85, lift: 2.4]\u000d\u000aassociation_rules = model.associationRules\u000d\u000a\u000d\u000a# Salvam intr-un tabel temporar pentru procesare ulterioara\u000d\u000aassociation_rules.createOrReplaceTempView("raw_rules")'),NULL,'Snippet: algoritm FPGrowth (Frequent Pattern Growth) pentru a găsi asocieri','{"language": "python"}');
INSERT INTO elements VALUES(85,51,3,'note_item','Acest cod rulează distribuit pe un cluster de Spark (pentru o implementare Enterprise) și procesează istoricul rapid.',NULL,'Note',NULL);
INSERT INTO elements VALUES(86,51,4,'note_item','Rezultatul brut trebuie rafinat cu reguli de business (guardrails) ulterior.',NULL,'Note',NULL);
INSERT INTO elements VALUES(87,51,5,'note_item','În pre-procesare se pot îndepărta produsele prea comune care sunt zgomot statistic (en. <em>noise</em>): ambalaje, consumabile, transportul dacă are SKU în ERP.',NULL,'Note',NULL);
INSERT INTO elements VALUES(88,52,1,'list_item','După ce există asocierile, logica sistemului de recomandări se aplică prin verificări. Exemplificăm cu <code>SQL</code> peste <code>Spark</code> un caz complex:',NULL,NULL,NULL);
