INSERT INTO elements VALUES(91,52,4,'list_item','Calculăm marja totală a asocierii (antecedent + consequent).',NULL,NULL,NULL);
INSERT INTO elements VALUES(92,52,5,'list_item','Avantajăm dintre bundleurile cu marjă totală pozitivă pe cele cu un produs în stoc peste 120 de zile.',NULL,NULL,NULL);
INSERT INTO elements VALUES(93,52,6,'code_snippet',unistr('WITH rule_financials AS (\u000d\u000a    SELECT \u000d\u000a        r.antecedent\u000d\u000a        , r.consequent\u000d\u000a        , r.confidence\u000d\u000a        -- COALESCE pentru a evita NULL\u000d\u000a        , SUM(COALESCE(p_ant.margin_eur, 0)) as antecedent_total_margin        \u000d\u000a        -- Verificam daca am gasit toate produsele din antecedent\u000d\u000a        , COUNT(p_ant.sku) as found_ant_products\u000d\u000a        , SIZE(r.antecedent) as expected_ant_products\u000d\u000a        , MAX(COALESCE(p_cons.margin_eur, 0)) as consequent_margin\u000d\u000a        , MAX(p_cons.days_in_inventory) as cons_days_inv\u000d\u000a    FROM raw_rules r\u000d\u000a    LATERAL VIEW explode(r.antecedent) a AS ant_sku\u000d\u000a    -- JOIN pentru antecedent\u000d\u000a    JOIN products p_ant ON a.ant_sku = p_ant.sku  \u000d\u000a    -- JOIN pentru consequent cu filtrare directa de stoc > 10 \u000d\u000a    JOIN products p_cons ON r.consequent[0] = p_cons.sku AND p_cons.stock_quantity > 10\u000d\u000a    GROUP BY \u000d\u000a        r.antecedent\u000d\u000a        , r.consequent\u000d\u000a        , r.confidence\u000d\u000a)\u000d\u000a\u000d\u000aSELECT\u000d\u000a    antecedent as current_basket\u000d\u000a    , consequent[0] as recommended_upsell\u000d\u000a    , confidence\u000d\u000a    , (antecedent_total_margin + consequent_margin) as total_bundle_margin\u000d\u000a    -- Calcul scor\u000d\u000a    , (confidence \u000d\u000a        * (antecedent_total_margin + consequent_margin) \u000d\u000a        * (CASE WHEN cons_days_inv > 120 THEN 1.5 ELSE 1.0 END)\u000d\u000a        ) as priority_score\u000d\u000aFROM rule_financials\u000d\u000aWHERE \u000d\u000a    -- la JOIN nu s-au pierdut produse din antecedent \u000d\u000a    found_ant_products = expected_ant_products\u000d\u000a    -- eliminam marjele negative sau zero (recomandat)\u000d\u000a    AND (antecedent_total_margin + consequent_margin) > 0\u000d\u000aORDER BY \u000d\u000a    priority_score DESC;'),NULL,'Snippet: sortare pachete după marjă și stoc vechi cu verificări de consistență ( Hive / Spark )','{"language": "sql"}');
INSERT INTO elements VALUES(94,52,7,'note_item','Statistica "clienții cumpără A+B" se combină cu logica companiei: "vindem A+B pentru că B e pe stoc de 120 de zile".',NULL,'Note',NULL);
INSERT INTO elements VALUES(95,52,8,'note_item','Rezultatele din acest raport (ex: zilnic) pot deveni <a href="/ai-2026/ghid-recomandari-upsell/cum-tehnologie-recomandari-ai/#dynamic-product-bundling">pachete reale de vânzare în e-commerce sau afiliați (Cap. 2.6.2.2)</a>.',NULL,'Note',NULL);
INSERT INTO elements VALUES(96,53,1,'list_item',unistr('Când agentul construiește o ofertă, sistemul poate propune automat pachete pe baza listelor de\u000d\u000a                        bundle-uri:'),NULL,NULL,NULL);
INSERT INTO elements VALUES(97,53,2,'code_snippet',unistr('def suggest_bundles_for_quote(\u000d\u000a    current_skus: list[str],\u000d\u000a    bundles: dict[tuple[str, str], int],\u000d\u000a    max_suggestions: int = 5,\u000d\u000a) -> list[tuple[str, str]]:\u000d\u000a    suggestions: list[tuple[str, str]] = []\u000d\u000a    seen: set[tuple[str, str]] = set()\u000d\u000a    current = set(current_skus)\u000d\u000a\u000d\u000a    for sku in current_skus:\u000d\u000a        for (a, b), _count in bundles.items():\u000d\u000a            pair = None\u000d\u000a\u000d\u000a            if sku == a and b not in current:\u000d\u000a                pair = (a, b)\u000d\u000a            elif sku == b and a not in current:\u000d\u000a                pair = (b, a)\u000d\u000a\u000d\u000a            if pair and pair not in seen:\u000d\u000a                seen.add(pair)\u000d\u000a                suggestions.append(pair)\u000d\u000a\u000d\u000a                if len(suggestions) >= max_suggestions:\u000d\u000a                    break\u000d\u000a\u000d\u000a        if len(suggestions) >= max_suggestions:\u000d\u000a            break\u000d\u000a\u000d\u000a    return suggestions'),NULL,unistr('Snippet: pseudocod care atribuie produselor curente\u000d\u000a                            bundle-uri precalculate'),'{"language": "python"}');
INSERT INTO elements VALUES(98,53,3,'note_item',unistr('Compania nu mai depinde de <a href="/ai-2026/ghid-recomandari-upsell/cum-tehnologie-recomandari-ai/#manual-organizational-knowledge">\u000d\u000a                                memoria agentului (Gen 0)</a> pentru a propune cross-sell, AI identifică tipare și în post-procesare regulile validează și ordonează pachetele conform politicii comerciale.'),NULL,'Note',NULL);
